module comparator_4bit (  
    input [3:0] A,  
    input [3:0] B,  
    output reg gte,  
    output reg gt,  
    output reg eq  
);  
    always @(*) begin  
        gte = 0;  
        gt = 0;  
        eq = 0;  
        if (A < B) begin  
            gte = 1;  
        end else if (A > B) begin  
            gt = 1;  
        end else begin  
            eq = 1;  
        end  
    end  
endmodule
